import Foundation

final class LicenseService {
    // MARK: - Bypass (set to false to enable license checking)
    static let LICENSE_BYPASS = true

    private let repository = LicenseRepository()
    private let trialKey = "zenspace_trial_start"

    func checkStatus() -> LicenseStatus {
        if Self.LICENSE_BYPASS { return .licensed }

        if let license = repository.load() {
            if let expiry = license.expiryDate, expiry < Date() {
                return .expired
            }
            return .licensed
        }

        if let trialStart = UserDefaults.standard.object(forKey: trialKey) as? Date {
            let hours = Int(Date().timeIntervalSince(trialStart) / 3600)
            let remaining = max(0, 72 - hours)
            return remaining > 0 ? .trial(remainingHours: remaining) : .expired
        }

        return .unlicensed
    }

    func startTrial() {
        UserDefaults.standard.set(Date(), forKey: trialKey)
    }

    func activate(key: String) -> Bool {
        if Self.LICENSE_BYPASS { return true }

        let license = License(
            licenseKey: key,
            deviceId: hardwareUUID(),
            deviceName: Host.current().localizedName,
            createdAt: Date(),
            expiryDate: nil,
            maxDevices: 3,
            activeDevices: 1
        )
        return repository.save(license)
    }

    func deactivate() -> Bool {
        repository.remove()
    }

    func currentLicense() -> License? {
        repository.load()
    }

    private func hardwareUUID() -> String {
        let service = IOServiceGetMatchingService(kIOMainPortDefault, IOServiceMatching("IOPlatformExpertDevice"))
        defer { IOObjectRelease(service) }
        guard let uuid = IORegistryEntryCreateCFProperty(service, "IOPlatformUUID" as CFString, kCFAllocatorDefault, 0)?
            .takeRetainedValue() as? String else {
            return UUID().uuidString
        }
        return uuid
    }
}

import AppKit
import Foundation

final class DisplayService {
    static let displayChanged = Notification.Name("com.zenspace.displayChanged")

    private let bundleID = "pro.betterdisplay.BetterDisplay"
    private var observer: NSObjectProtocol?

    private(set) var isBetterDisplayRunning: Bool = false

    func startMonitoring() {
        checkRunning()
        observer = NSWorkspace.shared.notificationCenter.addObserver(
            forName: NSWorkspace.didLaunchApplicationNotification,
            object: nil,
            queue: .main
        ) { [weak self] note in
            guard let app = note.userInfo?[NSWorkspace.applicationUserInfoKey] as? NSRunningApplication,
                  app.bundleIdentifier == self?.bundleID else { return }
            self?.isBetterDisplayRunning = true
            self?.postNotification(type: .launched)
        }

        NSWorkspace.shared.notificationCenter.addObserver(
            forName: NSWorkspace.didTerminateApplicationNotification,
            object: nil,
            queue: .main
        ) { [weak self] note in
            guard let app = note.userInfo?[NSWorkspace.applicationUserInfoKey] as? NSRunningApplication,
                  app.bundleIdentifier == self?.bundleID else { return }
            self?.isBetterDisplayRunning = false
            self?.postNotification(type: .terminated)
        }

        // Listen for BetterDisplay OSD notifications
        DistributedNotificationCenter.default().addObserver(
            self,
            selector: #selector(handleOSD(_:)),
            name: NSNotification.Name("com.betterdisplay.OSD"),
            object: nil
        )
    }

    func stopMonitoring() {
        if let observer { NSWorkspace.shared.notificationCenter.removeObserver(observer) }
        DistributedNotificationCenter.default().removeObserver(self)
    }

    func launchBetterDisplay() {
        guard let url = NSWorkspace.shared.urlForApplication(withBundleIdentifier: bundleID) else { return }
        NSWorkspace.shared.openApplication(at: url, configuration: .init())
    }

    private func checkRunning() {
        isBetterDisplayRunning = NSWorkspace.shared.runningApplications.contains {
            $0.bundleIdentifier == bundleID
        }
    }

    @objc private func handleOSD(_ notification: Notification) {
        postNotification(type: .osd)
    }

    private func postNotification(type: NotificationType) {
        NotificationCenter.default.post(name: Self.displayChanged, object: type)
    }
}

import AppKit
import Foundation

final class SoundService {
    enum Sound: String {
        case lock
        case unlock
        case lowBattery = "low-battery"
        case lowPower = "low-power"
        case chime
        case sleep
    }

    func play(_ sound: Sound) {
        guard let url = Bundle.main.url(forResource: sound.rawValue, withExtension: "caf")
                ?? Bundle.main.url(forResource: sound.rawValue, withExtension: "m4a") else { return }
        NSSound(contentsOf: url, byReference: true)?.play()
    }

    func startLockScreenObservation() {
        DistributedNotificationCenter.default().addObserver(
            self,
            selector: #selector(handleLock),
            name: NSNotification.Name("com.apple.screenIsLocked"),
            object: nil
        )
        DistributedNotificationCenter.default().addObserver(
            self,
            selector: #selector(handleUnlock),
            name: NSNotification.Name("com.apple.screenIsUnlocked"),
            object: nil
        )
    }

    @objc private func handleLock() {
        play(.lock)
    }

    @objc private func handleUnlock() {
        play(.unlock)
    }
}

