                    .font(.caption2)
                    .foregroundStyle(.green)
            } else if viewModel.isLowBattery {
                Text("notification.battery.lowBattery")
                    .font(.caption2)
                    .foregroundStyle(.red)
            }
        }
        .onAppear { viewModel.start() }
    }
}

