    }
}

import SwiftUI
import AppKit

struct NotchView<Content: View>: View {
    @State private var isExpanded = false
    @State private var isHovering = false
    let content: () -> Content

    init(@ViewBuilder content: @escaping () -> Content) {
        self.content = content
    }

    var body: some View {
        content()
            .clipShape(RoundedRectangle(cornerRadius: isExpanded ? 16 : 12))
            .glassEffect(material: .popover)
            .scaleEffect(isHovering ? 1.02 : 1.0)
            .animation(.spring(response: 0.3, dampingFraction: 0.7), value: isExpanded)
            .animation(.easeInOut(duration: 0.15), value: isHovering)
            .onHover { hovering in
                isHovering = hovering
            }
            .onTapGesture {
                withAnimation { isExpanded.toggle() }
            }
    }
}

// MARK: - NotchWindow controller for positioning at screen notch

final class NotchWindowController {
    private var window: NSWindow?

    func show(with view: some View) {
        guard let screen = NSScreen.main else { return }
        let notchWidth: CGFloat = 300
        let notchHeight: CGFloat = 400

        let x = screen.frame.midX - notchWidth / 2
        let y = screen.frame.maxY - notchHeight - 4

        let hostingView = NSHostingView(rootView: view)
        let window = NSWindow(
            contentRect: NSRect(x: x, y: y, width: notchWidth, height: notchHeight),
            styleMask: [.borderless],
            backing: .buffered,
            defer: false
        )
        window.contentView = hostingView
        window.isOpaque = false
        window.backgroundColor = .clear
        window.level = .statusBar
        window.collectionBehavior = [.canJoinAllSpaces, .stationary]
        window.hasShadow = true
        window.orderFrontRegardless()

        self.window = window
    }

    func dismiss() {
        window?.close()
        window = nil
    }
}

import SwiftUI
import AppKit

struct ProgressiveBlurView: View {
    var direction: Direction = .topToBottom
    var steps: Int = 6
    var maxRadius: CGFloat = 20

    enum Direction {
        case topToBottom, bottomToTop
    }

    var body: some View {
        GeometryReader { geo in
            VStack(spacing: 0) {
                let orderedSteps = direction == .topToBottom
                    ? Array(0..<steps)
                    : Array((0..<steps).reversed())

                ForEach(orderedSteps, id: \.self) { step in
                    let fraction = CGFloat(step) / CGFloat(steps - 1)
                    let radius = maxRadius * fraction
                    Rectangle()
                        .fill(.clear)
                        .frame(height: geo.size.height / CGFloat(steps))
                        .blur(radius: radius)
                        .background(
                            GlassEffectView(material: .hudWindow, blendingMode: .behindWindow)
                                .opacity(Double(fraction))
                        )
                }
            }
        }
        .allowsHitTesting(false)
    }
}

extension View {
    func progressiveBlur(
        direction: ProgressiveBlurView.Direction = .bottomToTop,
        maxRadius: CGFloat = 20
    ) -> some View {
        overlay(alignment: direction == .bottomToTop ? .bottom : .top) {
            ProgressiveBlurView(direction: direction, maxRadius: maxRadius)
                .frame(height: 40)
        }
    }
}

import Foundation
import AppKit

final class FocusService {
    static let focusChanged = Notification.Name("com.zenspace.focusChanged")

    private var timer: Timer?

    func startMonitoring() {
        checkCurrentMode()
        timer = Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { [weak self] _ in
            self?.checkCurrentMode()
        }
    }

    func stopMonitoring() {
        timer?.invalidate()
        timer = nil
    }

    func getCurrentMode() -> FocusMode? {
        // Uses NSDoNotDisturbEnabled from UserDefaults (com.apple.controlcenter)
        // For full Focus mode detection, we check the DND state
        let dndEnabled = isDNDEnabled()
        return dndEnabled ? .doNotDisturb : nil
    }

    private func isDNDEnabled() -> Bool {
        // Check DND via distributed notification center defaults
        guard let defaults = UserDefaults(suiteName: "com.apple.controlcenter") else { return false }
        return defaults.bool(forKey: "NSDoNotDisturbEnabled")
    }

    private func checkCurrentMode() {
        NotificationCenter.default.post(name: Self.focusChanged, object: getCurrentMode())
    }
}

