struct AboutSettingsTab: View {
    @State private var updateState: UpdateService.UpdateState = .idle
    @State private var isChecking = false

    var body: some View {
        VStack(spacing: 12) {
            Image(systemName: "brain.head.profile")
                .font(.system(size: 48))
                .foregroundStyle(.secondary)
            Text("ZenSpace")
                .font(.title2)
                .fontWeight(.semibold)
            Text("common.version")
                .font(.caption)
                .foregroundStyle(.secondary)

            Divider()

            updateSection
        }
        .padding()
    }

    @ViewBuilder
    private var updateSection: some View {
        switch updateState {
        case .idle:
            Button("settings.about.checkUpdates") { checkForUpdate() }
                .buttonStyle(.bordered)
                .disabled(isChecking)
        case .checking:
            ProgressView()
                .controlSize(.small)
            Text("common.waiting")
                .font(.caption)
        case .available(let release):
            Text("v\(release.version) available")
                .font(.caption)
                .foregroundStyle(.green)
            Button("common.updateNow") { install(release: release) }
                .buttonStyle(.borderedProminent)
        case .upToDate:
            Label("Up to date", systemImage: "checkmark.circle.fill")
                .font(.caption)
                .foregroundStyle(.green)
        case .downloading(let progress):
            ProgressView(value: progress)
                .frame(width: 150)
        case .installing:
            Text("Installing...")
                .font(.caption)
        case .error(let msg):
            Text(msg)
                .font(.caption)
                .foregroundStyle(.red)
            Button("settings.about.checkUpdates") { checkForUpdate() }
                .buttonStyle(.bordered)
        }
    }

    private func checkForUpdate() {
        isChecking = true
        updateState = .checking
        Task {
            updateState = await UpdateService.shared.checkForUpdate()
            isChecking = false
        }
    }

    private func install(release: UpdateService.Release) {
        updateState = .downloading(0)
        Task {
            updateState = await UpdateService.shared.downloadAndInstall(release: release)
        }
    }
}

import SwiftUI
import EventKit

struct PermissionsView: View {
    @State private var calendarStatus: EKAuthorizationStatus = .notDetermined
    @State private var accessibilityGranted = false

    var body: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text("settings.section.notifications")
                .font(.headline)

            PermissionRow(
                title: "common.calendar",
                icon: "calendar",
                granted: calendarStatus == .authorized,
                action: requestCalendar
            )

            PermissionRow(
                title: "common.nowPlaying",
                icon: "music.note",
                granted: true, // Media doesn't require explicit permission on macOS
                action: {}
            )

            PermissionRow(
                title: "Accessibility",
                icon: "accessibility",
                granted: accessibilityGranted,
                action: openAccessibility
            )

            PermissionRow(
                title: "Bluetooth",
                icon: "wave.3.right",
                granted: true, // Checked at runtime
                action: {}
            )
        }
        .padding()
        .onAppear { checkPermissions() }
    }

    private func checkPermissions() {
        calendarStatus = EKEventStore.authorizationStatus(for: .event)
        accessibilityGranted = AXIsProcessTrusted()
    }

    private func requestCalendar() {
        Task {
            let store = EKEventStore()
            if #available(macOS 14.0, *) {
                _ = try? await store.requestFullAccessToEvents()
            } else {
                _ = await withCheckedContinuation { cont in
                    store.requestAccess(to: .event) { granted, _ in cont.resume(returning: granted) }
                }
            }
            calendarStatus = EKEventStore.authorizationStatus(for: .event)
        }
    }

    private func openAccessibility() {
        let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility")!
        NSWorkspace.shared.open(url)
    }
}

struct PermissionRow: View {
    let title: LocalizedStringKey
    let icon: String
    let granted: Bool
